WHERE u.del_flag = 0



        AND (
            u.username LIKE CONCAT('%', #{username}, '%')
            OR u.nickname LIKE CONCAT('%', #{nickname}, '%')
        )



            AND u.username LIKE CONCAT('%', #{username}, '%')


            AND u.nickname LIKE CONCAT('%', #{nickname}, '%')




    AND u.status = #{status}


    AND u.dept_id = #{deptId}
